import React from 'react';
import {
  Card,
  Stack,
  Box,
  Divider,
  Heading,
  Text,
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<ForecastItem>;
}

/**
 * WeatherCard - A widget displaying current weather and a multi-day forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  const isSunny = (condition || '').toLowerCase().includes('sunny') || (condition || '').toLowerCase().includes('clear');

  return (
    <Card>
      <Stack>
        {/* Main Content Area */}
        <Box
          padding="24px"
          background={isSunny ? 'var(--ggui-color-primary-container)' : 'var(--ggui-color-surface-container-low)'}
        >
          <Stack gap="24px">
            {/* Header: City and Condition */}
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={2}>
                {city}
              </Heading>
              <Text variant="bodyLarge" weight="medium">
                {condition}
              </Text>
            </Stack>

            {/* Main Temperature Section */}
            <Stack gap="4px">
              <Heading level={1}>
                {temperature}°{unit}
              </Heading>

              {/* Secondary Details */}
              <Stack direction="horizontal" gap="16px" align="center">
                <Stack direction="horizontal" gap="4px" align="center">
                  <Text variant="bodySmall">
                    Humidity:
                  </Text>
                  <Text
                    variant="bodySmall"
                    weight="semibold"
                    color="var(--ggui-color-primary)"
                  >
                    {humidity}%
                  </Text>
                </Stack>
                <Stack direction="horizontal" gap="4px" align="center">
                  <Text variant="bodySmall">
                    Wind:
                  </Text>
                  <Text
                    variant="bodySmall"
                    weight="semibold"
                    color="var(--ggui-color-primary)"
                  >
                    {windSpeed} km/h
                  </Text>
                </Stack>
              </Stack>
            </Stack>
          </Stack>
        </Box>

        <Divider />

        {/* 5-Day Forecast Strip */}
        <Box padding="16px 24px 24px 24px">
          <Stack direction="horizontal" justify="between" align="center" gap="8px">
            {forecast.map((item, index) => (
              <Stack key={index} align="center" gap="4px">
                <Text variant="label">
                  {item.day ?? '---'}
                </Text>
                <Box padding="4px">
                  <Text variant="bodyLarge">
                    {item.icon ?? '☁️'}
                  </Text>
                </Box>
                <Stack direction="horizontal" gap="4px" justify="center">
                  <Text variant="bodySmall" weight="semibold">
                    {item.high ?? 0}°
                  </Text>
                  <Text variant="bodySmall">
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}
